static constexpr uint32_t UB_BUDGET_BYTES = 192 * 1024;
static constexpr uint32_t ALIGN_ELEMS = 8;   // 32 bytes align for float

static inline uint32_t AlignDown(uint32_t x, uint32_t a) { return (x / a) * a; }

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    TripletMarginLossCustomTilingData tiling;
    const uint32_t totalTriplets = static_cast<uint32_t>(context->GetInputShape(0)->GetOriginShape().GetShapeSize());
    // All inputs have same shape: (N, D)
